<template>
    <div>
        <div id="step1">第一步：使用intro.js进行页面引导</div>
        <div id="step2">第二步：123</div>
        <div id="step3">第三步：123</div>
        <div id="step4">第四步：123</div>
        <el-button type="text" @click="start" id="step5">开始引导</el-button>
    </div>
</template>
<script>
    export default {
        methods: {
            start() {
                this.$nextTick(() => {
                    require('intro.js')().setOptions({
                        prevLabel: "上一步",
                        nextLabel: "下一步",
                        skipLabel: "×",
                        doneLabel: "结束",
                        steps: [1, 2, 3, 4, 5].map(e => ({
                            element: '#step' + e,
                            intro: '这是第' + e + '步'
                        }))
                    }).start();
                });
            }
        }
    }
</script>
